import { useState } from 'react'

export default function DropZone({ onFileSelect }) {
  const [isDragging, setIsDragging] = useState(false)

  const handleDragOver = (e) => {
    e.preventDefault()
    setIsDragging(true)
  }

  const handleDragLeave = () => setIsDragging(false)

  const handleDrop = (e) => {
    e.preventDefault()
    setIsDragging(false)
    const file = e.dataTransfer.files[0]
    if (file) onFileSelect(file)
  }

  const handleChange = (e) => {
    const file = e.target.files[0]
    if (file) onFileSelect(file)
  }

  return (
    <div
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
      className={`border-2 border-dashed rounded-xl p-12 text-center cursor-pointer transition-colors duration-200 ${
        isDragging 
          ? 'border-indigo-500 bg-indigo-50' 
          : 'border-gray-300 hover:border-indigo-400 bg-gray-50 hover:bg-indigo-50'
      }`}
    >
      <input type="file" onChange={handleChange} accept=".jpg,.jpeg,.png,.pdf" className="hidden" id="file-input" />
      <label htmlFor="file-input" className="cursor-pointer">
        <div className="text-4xl mb-4">↑</div>
        <p className="text-sm text-gray-700 mb-2">영수증을 드래그하거나 클릭하여 업로드하세요</p>
        <p className="text-xs text-gray-500">JPG, PNG, PDF · 최대 10MB</p>
      </label>
    </div>
  )
}
