```jsx
import { useState } from 'react'
import { useNavigate } from 'react-router-dom'
import Header from '../components/Header'
import DropZone from '../components/DropZone'
import ProgressBar from '../components/ProgressBar'
import ParsePreview from '../components/ParsePreview'
import Toast from '../components/Toast'
import { uploadReceipt } from '../api/client'

export default function UploadPage() {
  const navigate = useNavigate()
  const [isUploading, setIsUploading] = useState(false)
  const [parsedData, setParsedData] = useState(null)
  const [toast, setToast] = useState(null)

  const handleFileSelect = async (file) => {
    setIsUploading(true)
    setParsedData(null)

    try {
      const formData = new FormData()
      formData.append('file', file)

      const { data } = await uploadReceipt(formData)
      setParsedData(data)
    } catch (error) {
      setToast({ type: 'error', message: error.response?.data?.detail || '업로드 실패' })
    } finally {
      setIsUploading(false)
    }
  }

  const handleSave = (data) => {
    // localStorage 병행 저장
    const expenses = JSON.parse(localStorage.getItem('expenses') || '[]')
    expenses.push(data)
    localStorage.setItem('expenses', JSON.stringify(expenses))

    setToast({ type: 'success', message: '저장되었습니다!' })
    setTimeout(() => navigate('/'), 1000)
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <Header />
      <div className="max-w-4xl mx-auto px-4 py-6">
        <h2 className="text-2xl font-bold mb-6">영수증 업로드</h2>

        <DropZone onFileSelect={handleFileSelect} />

        {isUploading && (
          <div className="mt-6">
            <ProgressBar progress={50} />
          </div>
        )}

        {parsedData && (
          <div className="mt-6">
            <ParsePreview 
              data={parsedData} 
              onSave={handleSave}
              onCancel={() => setParsedData(null)}
            />
          </div>
        )}
      </div>

      {toast && <Toast {...toast} onClose={() => setToast(null)} />}
    </div>
  )
}
```

