import { useState, useEffect } from 'react'
import Header from '../components/Header'
import SummaryCard from '../components/SummaryCard'
import FilterBar from '../components/FilterBar'
import ExpenseCard from '../components/ExpenseCard'
import { getExpenses, getSummary } from '../api/client'

export default function Dashboard() {
  const [expenses, setExpenses] = useState([])
  const [summary, setSummary] = useState({})
  const [filters, setFilters] = useState({})

  useEffect(() => {
    loadData()
  }, [filters])

  const loadData = async () => {
    try {
      const [expensesRes, summaryRes] = await Promise.all([
        getExpenses(filters),
        getSummary()
      ])

      // localStorage와 서버 데이터 병합
      const localExpenses = JSON.parse(localStorage.getItem('expenses') || '[]')
      setExpenses([...expensesRes.data, ...localExpenses])
      setSummary(summaryRes.data)
    } catch (error) {
      console.error('데이터 로드 실패:', error)
    }
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <Header />
      <div className="max-w-4xl mx-auto px-4 py-6">
        <div className="grid grid-cols-2 gap-4 mb-6">
          <SummaryCard title="총 지출" amount={summary.total_amount} />
          <SummaryCard title="이번달 지출" amount={summary.this_month_amount} />
        </div>

        <FilterBar onFilter={setFilters} />

        <h2 className="text-lg font-semibold mt-6 mb-4">지출 내역 ({expenses.length}건)</h2>

        {expenses.length === 0 ? (
          <div className="text-center py-12">
            <p className="text-gray-500 mb-4">아직 등록된 지출 내역이 없습니다</p>
            <p className="text-gray-400 text-sm">영수증을 업로드해 보세요</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            {expenses.map(expense => (
              <ExpenseCard key={expense.id} expense={expense} />
            ))}
          </div>
        )}
      </div>
    </div>
  )
}
```

src/pages/ExpenseDetail.jsx:
```jsx
import { useState, useEffect } from 'react'
import { useParams, useNavigate } from 'react-router-dom'
import Header from '../components/Header'
import Modal from '../components/Modal'
import Toast from '../components/Toast'
import Badge from '../components/Badge'
import { getExpenses, deleteExpense, updateExpense } from '../api/client'

export default function ExpenseDetail() {
  const { id } = useParams()
  const navigate = useNavigate()
  const [expense, setExpense] = useState(null)
  const [isEditing, setIsEditing] = useState(false)
  const [formData, setFormData] = useState({})
  const [showDeleteModal, setShowDeleteModal] = useState(false)
  const [toast, setToast] = useState(null)

  useEffect(() => {
    loadExpense()
  }, [id])

  const loadExpense = async () => {
    try {
      const { data } = await getExpenses()
      const found = data.find(exp => exp.id === id)

      if (!found) {
        const local = JSON.parse(localStorage.getItem('expenses') || '[]')
        const localFound = local.find(exp => exp.id === id)
        if (localFound) {
          setExpense(localFound)
          setFormData(localFound)
        }
      } else {
        setExpense(found)
        setFormData(found)
      }
    } catch (error) {
      console.error('로드 실패:', error)
    }
  }

  const handleDelete = async () => {
    try {
      await deleteExpense(id)
      setToast({ type: 'success', message: '삭제되었습니다' })
      setTimeout(() => navigate('/'), 1000)
    } catch (error) {
      setToast({ type: 'error', message: '삭제 실패' })
    }
  }

  const handleSave = async () => {
    try {
      await updateExpense(id, formData)
      setExpense(formData)
      setIsEditing(false)
      setToast({ type: 'success', message: '수정되었습니다' })
    } catch (error) {
      setToast({ type: 'error', message: '수정 실패' })
    }
  }

  if (!expense) return <div>로딩 중...</div>

  return (
    <div className="min-h-screen bg-gray-50">
      <Header />
      <div className="max-w-4xl mx-auto px-4 py-6">
        <div className="bg-white rounded-xl border border-gray-200 shadow-sm p-6">
          <div className="flex items-start justify-between mb-4">
            <div>
              <h2 className="text-xl font-bold">{expense.store_name}</h2>
              <Badge category={expense.category} />
            </div>
            <button onClick={() => setIsEditing(!isEditing)} className="text-indigo-600 hover:text-indigo-700 font-medium text-sm">수정</button>
          </div>

          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">날짜</label>
              {isEditing ? (
                <input type="date" value={formData.receipt_date} onChange={(e) => setFormData({...formData, receipt_date: e.target.value})} className="w-full px-3 py-2 border border-gray-300 rounded-lg" />
              ) : (
                <p className="text-gray-900">{expense.receipt_date}</p>
              )}
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">합계</label>
              <p className="text-2xl font-bold text-gray-900">₩ {(expense.total_amount || 0).toLocaleString()}</p>
            </div>
          </div>

          <div className="flex gap-2 mt-6">
            <button onClick={() => setShowDeleteModal(true)} className="bg-red-500 hover:bg-red-600 text-white font-semibold py-2 px-4 rounded-lg transition-colors">삭제</button>
            {isEditing && <button onClick={handleSave} className="ml-auto bg-indigo-600 hover:bg-indigo-700 text-white font-semibold py-2 px-4 rounded-lg transition-colors">수정 저장</button>}
          </div>
        </div>
      </div>

      {showDeleteModal && (
        <Modal 
          title="지출 삭제"
          message="정말 삭제하시겠습니까?"
          onConfirm={handleDelete}
          onCancel={() => setShowDeleteModal(false)}
        />
      )}

      {toast && <Toast {...toast} onClose={() => setToast(null)} />}
    </div>
  )
}
```

